  "phase": "question",
  "questions": [
    {
      "id": "q1",
      "question": "Should useAssumptions be mocked at module level, or should the test wrap VariableRow in a real AssumptionProvider (like AssumptionPanel.test.tsx does with its Seeder pattern) to test assumption toggle integration?",
      "category": "design",
      "why_it_matters": "Using a real AssumptionProvider lets us verify that handleAssume actually adds/removes assumptions via context, but mocking gives more isolated unit tests. The task says 'assumption toggle callback' which could mean either."
    },
    {
      "id": "q2",
      "question": "Does crypto.randomUUID() work in the jsdom test environment, or does it need a mock/polyfill?",
      "category": "codebase",
      "why_it_matters": "handleSubmitEdit calls crypto.randomUUID() for idempotencyKey. If jsdom doesn't provide it, edit-submission tests will throw at runtime."
    },
    {
      "id": "q3",
      "question": "Should the edit flow tests verify the exact mutation payload shape (accountId, variableId, target, context, session), or just verify mutation.mutate was called?",
      "category": "requirements",
      "why_it_matters": "The mutation payload includes conditional logic (isTargetMarket determines which variableId is used) and the context from useAssumptions. Testing payload shape catches regressions in that logic but couples the test to implementation details."
    },
    {
      "id": "q4",
      "question": "Should we test the mutation success/error message rendering (lines 162-171), or is that out of scope given the task description focuses on 'rendering, outcome selection, assumption toggle'?",
      "category": "requirements",
      "why_it_matters": "The task description mentions three specific behaviors but mutation feedback is a visible UI feature. Including it adds coverage but may exceed scope."
    }
  ],
  "assumptions": [
    {
      "id": "a1",
      "assumption": "Mock useMarket, useSession, and useProbabilityEdit at module level; use a real AssumptionProvider with the Seeder pattern for assumption tests (matches the proven pattern in AssumptionPanel.test.tsx).",
      "confidence": 0.85,
      "if_wrong": "Would need to restructure all tests to either fully mock or fully integrate useAssumptions. Low risk since the Seeder pattern is already validated in the codebase."
    },
    {
      "id": "a2",
      "assumption": "crypto.randomUUID() is available in the jsdom environment (Node 19+ provides it globally, and the project uses modern Node).",
